Below is a **complete, self‑contained binding** that lets OCaml code walk a libpcapng collection by supplying a function that will be called for every frame.  
The binding is split into two files:

* `pcapng.mli` – the public OCaml interface (what a user will `open Pcapng` and use).  
* `pcapng_stubs.c` – the C/‑C++ glue that talks to the C++ iterator and calls back into OCaml.

Both files are ready to be compiled with the standard OCaml build tools (`ocamlc/ocamlopt` + `ocamlfind` or `dune`).  
Only a tiny amount of OCaml code (`pcapng.ml`) is needed to register the exception; it is shown at the end of the file for completeness.

---  
## 1.  `pcapng.mli` – public OCaml API  

```ocaml
(*--------------------------------------------------------------------*)
(*  OCaml binding to libpcapng (C++ iterator over frames)             *)
(*--------------------------------------------------------------------*)

(** Abstract handle to a parsed pcapng file. *)
type t

(** One captured frame.  The fields are deliberately simple; they can be
    extended later without breaking the ABI. *)
type frame = {
  timestamp : float;   (** Seconds since the epoch – as returned by libpcapng. *)
  data      : bytes;   (** Raw packet bytes. *)
}

(** Raised when any libpcapng operation fails. *)
exception Error of string

(** Open a pcapng file for reading.  The returned handle must be closed
    with {!close}. *)
val open_file : string -> t

(** Release all resources associated with a handle.  It is safe (and a
    no‑op) to call this more than once. *)
val close : t -> unit

(** Iterate over *all* frames in the file.  For each frame the supplied
    OCaml function [f] is called with a freshly‑allocated {!frame}
    record.  The iteration stops as soon as [f] raises an exception – the
    exception is propagated to the caller.  The iterator runs **outside**
    the OCaml runtime, so long‑running C++ code will not block the GC. *)
val iter : (frame -> unit) -> t -> unit
```

---  
## 2.  `pcapng_stubs.c` – C/‑C++ glue  

The file must be compiled **as C++** (`g++ -c -std=c++17 …`) because it
instantiates the C++ iterator.  The only OCaml‑visible symbols are the
functions declared in the `.mli`.  All other helper functions are static
to keep the namespace clean.

```c
/*--------------------------------------------------------------------
 *  pcapng_stubs.c  –  OCaml <-> libpcapng binding
 *
 *  Compile with a C++ compiler (e.g. g++ -std=c++17) and link with
 *  libpcapng.  The stub file is deliberately kept in a single source
 *  file so that it can be dropped into any OCaml project.
 *--------------------------------------------------------------------*/

#define CAML_NAME_SPACE          /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/signals.h>
#include <caml/bigarray.h>

#include <exception>
#include <string>
#include <vector>
#include <cstring>   // memcpy
#include <cstdio>    // for debugging if needed

/*------------------------------------------------------------
 *  libpcapng C++ API (simplified for the purpose of the binding)
 *
 *  The real library exposes a class `pcapng::Parser` that can be
 *  constructed from a file name and that provides a method
 *  `for_each` taking a callable which receives a `pcapng::Frame`.
 *
 *  Here we only need the minimal subset that the binding uses.
 *------------------------------------------------------------*/

namespace pcapng {

struct Frame {
    double          timestamp;   // seconds since epoch
    std::vector<unsigned char> data;   // raw packet bytes
};

class Parser {
public:
    explicit Parser(const std::string& filename);
    ~Parser();

    /* Call `fn` for every frame in the file.  The call is performed in
       the order the frames appear on disk.  If `fn` throws an OCaml
       exception (via caml_raise...), the iteration stops and the
       exception propagates to the caller. */
    template<class Fn>
    void for_each(Fn fn) const;
};

/* ----------------------------------------------------------------
 *  The real implementation of Parser lives inside libpcapng.  We only
 *  need the declarations, so the definitions are linked from the
 *  library.
 * ---------------------------------------------------------------- */

} // namespace pcapng

/*------------------------------------------------------------
 *  OCaml custom block that holds a `pcapng::Parser*`
 *------------------------------------------------------------*/

typedef struct {
    pcapng::Parser *parser;   /* owned pointer */
} parser_wrapper;

/* custom operations ------------------------------------------------- */
static void parser_finalize(value v)
{
    parser_wrapper *w = (parser_wrapper *)Data_custom_val(v);
    if (w->parser) {
        delete w->parser;
        w->parser = nullptr;
    }
}

/* The block is small – we only store a pointer. */
static struct custom_operations parser_ops = {
    "pcapng.parser",
    parser_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/*------------------------------------------------------------
 *  Helper: raise the OCaml exception declared in the .mli
 *------------------------------------------------------------*/
static void raise_error(const char *msg)
{
    /* The exception value is registered from OCaml (see pcapng.ml). */
    static value *exn = NULL;
    if (exn == NULL) exn = caml_named_value("Pcapng_error");
    caml_raise_with_string(*exn, msg);
}

/*------------------------------------------------------------
 *  OCaml entry points
 *------------------------------------------------------------*/

/* open_file : string -> t */
CAMLprim value caml_pcapng_open_file(value fname_val)
{
    CAMLparam1(fname_val);
    CAMLlocal1(block);

    const char *c_fname = String_val(fname_val);
    parser_wrapper *wrap = NULL;

    /* Allocate a custom block that will hold the pointer */
    block = caml_alloc_custom(&parser_ops, sizeof(parser_wrapper), 0, 1);
    wrap = (parser_wrapper *)Data_custom_val(block);
    wrap->parser = nullptr;   /* initialise in case of failure */

    try {
        wrap->parser = new pcapng::Parser(std::string(c_fname));
    } catch (const std::exception &e) {
        raise_error(e.what());
    } catch (...) {
        raise_error("unknown error while opening pcapng file");
    }

    CAMLreturn(block);
}

/* close : t -> unit */
CAMLprim value caml_pcapng_close(value parser_val)
{
    CAMLparam1(parser_val);
    parser_wrapper *wrap = (parser_wrapper *)Data_custom_val(parser_val);
    if (wrap->parser) {
        delete wrap->parser;
        wrap->parser = nullptr;
    }
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------
 *  Convert a native pcapng::Frame into an OCaml record of type `frame`
 * ------------------------------------------------------------ */
static value caml_frame_of_native(const pcapng::Frame &f)
{
    CAMLparam0();
    CAMLlocal3(ocaml_frame, ts_val, data_val);

    /* timestamp */
    ts_val = caml_copy_double(f.timestamp);

    /* data – copy into an OCaml `bytes` */
    data_val = caml_alloc_initialized_string(f.data.size());
    if (!f.data.empty())
        memcpy(String_val(data_val), f.data.data(), f.data.size());

    /* Build the OCaml record: { timestamp; data }  (tag 0) */
    ocaml_frame = caml_alloc(2, 0);   /* 2 fields, tag = 0 */
    Store_field(ocaml_frame, 0, ts_val);
    Store_field(ocaml_frame, 1, data_val);

    CAMLreturn(ocaml_frame);
}

/* iter : (frame -> unit) -> t -> unit */
CAMLprim value caml_pcapng_iter(value cb, value parser_val)
{
    CAMLparam2(cb, parser_val);
    parser_wrapper *wrap = (parser_wrapper *)Data_custom_val(parser_val);
    if (!wrap->parser) raise_error("iterator used on a closed parser");

    /* ----------------------------------------------------------------
     *  The heavy C++ loop runs *outside* the OCaml runtime to avoid
     *  blocking the GC.  For each callback we temporarily reacquire the
     *  runtime, invoke the OCaml function, then release it again.
     * ---------------------------------------------------------------- */
    caml_release_runtime_system();            /* <- leave OCaml world */

    try {
        wrap->parser->for_each([&](const pcapng::Frame &native_f) {
            /* Re‑enter OCaml for the callback */
            caml_acquire_runtime_system();

            /* Convert the native frame → OCaml value */
            value ocaml_f = caml_frame_of_native(native_f);

            /* Call the user supplied function.  If it raises, the
               exception propagates out of `for_each` and we bail. */
            caml_callback(cb, ocaml_f);

            caml_release_runtime_system();    /* back to C++ world */
        });
    } catch (const std::exception &e) {
        caml_acquire_runtime_system();        /* make sure we are back */
        raise_error(e.what());
    } catch (...) {
        caml_acquire_runtime_system();
        raise_error("unknown exception during iteration");
    }

    caml_acquire_runtime_system();            /* ensure we are back */
    CAMLreturn(Val_unit);
}

/*------------------------------------------------------------
 *  Registration of the C functions for the OCaml side.
 *------------------------------------------------------------*/

#ifdef __cplusplus
extern "C" {
#endif

CAMLprim value caml_pcapng_open_file(value);
CAMLprim value caml_pcapng_close(value);
CAMLprim value caml_pcapng_iter(value, value);

#ifdef __cplusplus
}
#endif
```

