## 3.  Minimal `pcapng.ml` (only needed to register the exception)

```ocaml
(* pcapng.ml – tiny wrapper that registers the exception for the C stub *)

let () =
  (* The C stub looks up the exception by this name. *)
  Callback.register_exception "Pcapng_error" (Error "")
```

---  
## 4.  How to build  

A typical `dune` stanza (or a `Makefile`) would look like:

```dune
(library
 (name pcapng)
 (public_name pcapng)
 (foreign_stubs
  (language c)
  (names pcapng_stubs)
  (flags (:standard -std=c++17))
  (include_dirs <path-to-libpcapng-headers>)
  (extra_libs pcapng))   ; link with libpcapng
 (modules pcapng)         ; the .ml file that registers the exception
 (libraries camlidl)      ; (optional) if you need additional support
)
```

If you prefer a manual `Makefile`:

```make
OCAMLFLAGS = -I +camllib
CXXFLAGS   = -std=c++17 -fPIC -I/path/to/libpcapng/include
LDFLAGS    = -lpcapng

pcapng.cma: pcapng.cmi pcapng.cmo libpcapng_stubs.o
    ocamlc -a -o $@ $^

pcapng.cmi pcapng.cmo: pcapng.mli pcapng.ml
    ocamlc -c $<

libpcapng_stubs.o: pcapng_stubs.c
    g++ $(CXXFLAGS) -c $< -o $@

clean:
    rm -f *.cmi *.cmo *.o *.cma
```

---  
## 5.  Using the binding (example)

```ocaml
open Pcapng

let () =
  let handle = open_file "sample.pcapng" in
  try
    iter (fun frame ->
        Printf.printf "Got frame @ %.3f, %d bytes\n%!"
          frame.timestamp (Bytes.length frame.data)
      ) handle
  with
  | Error msg -> prerr_endline ("pcapng error: " ^ msg)
  finally
    close handle
```

The user supplies a normal OCaml function; the C++ iterator calls it for each frame, passing a freshly‑allocated record that the user can inspect or process.  Errors from the C++ library are turned into the `Error` exception, and any exception raised by the user‑function stops the iteration and bubbles back to the caller.

That’s it – a clean, idiomatic OCaml binding that lets OCaml code “drive” a C++ iterator.
